1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
5	import { AssumptionProvider, useAssumptions } from "@/features/assumptions/AssumptionContext";
6	import type { Market } from "@/lib/api/types";
7	
8	// ---------------------------------------------------------------------------
9	// Mocks
10	// ---------------------------------------------------------------------------
11	
12	vi.mock("@/features/assumptions/VariableRow", () => ({
13	  VariableRow: vi.fn(({ marketId, targetMarket }: { marketId: string; targetMarket: Market }) => (
14	    <div data-testid={`variable-row-${marketId}`}>
15	      VariableRow: {marketId} (target: {targetMarket.id})
16	    </div>
17	  )),
18	}));
19	
20	vi.mock("@/lib/query/hooks", () => ({
21	  useMarkets: vi.fn(),
22	}));
23	
24	import { useMarkets } from "@/lib/query/hooks";
25	import { VariableRow } from "@/features/assumptions/VariableRow";
26	
27	const mockUseMarkets = vi.mocked(useMarkets);
28	const mockVariableRow = vi.mocked(VariableRow);
29	
30	// ---------------------------------------------------------------------------
31	// Fixtures
32	// ---------------------------------------------------------------------------
33	
34	const currentMarket: Market = {
35	  id: "mkt-current",
36	  title: "Will it rain?",
37	  description: "Rain forecast",
38	  variableId: "var-rain",
39	  status: "active",
40	  outcomes: [
41	    { id: "out-yes", name: "Yes" },
42	    { id: "out-no", name: "No" },
43	  ],
44	  marginals: { "out-yes": 0.6, "out-no": 0.4 },
45	  liquidity: 1000,
46	  volume: 500,
47	  created_at: "2026-01-01T00:00:00Z",
48	  expires_at: "2026-12-31T00:00:00Z",
49	};
50	
51	function makeMarket(id: string, title: string): Market {
52	  return {
53	    id,
54	    title,
55	    description: `${title} description`,
56	    variableId: `var-${id}`,
57	    status: "active",
58	    outcomes: [
59	      { id: `${id}-yes`, name: "Yes" },
60	      { id: `${id}-no`, name: "No" },
61	    ],
62	    marginals: { [`${id}-yes`]: 0.5, [`${id}-no`]: 0.5 },
63	    liquidity: 100,
64	    volume: 50,
65	    created_at: "2026-01-01T00:00:00Z",
66	    expires_at: "2026-12-31T00:00:00Z",
67	  };
68	}
69	
70	const marketB = makeMarket("mkt-b", "Market B");
71	const marketC = makeMarket("mkt-c", "Market C");
72	
73	function threeActiveMarkets() {
74	  return {
75	    data: {
76	      markets: [currentMarket, marketB, marketC],
77	    },
78	    isLoading: false,
79	    isError: false,
80	    error: null,
81	  } as unknown as ReturnType<typeof useMarkets>;
82	}
83	
84	function singleActiveMarket() {
85	  return {
86	    data: { markets: [currentMarket] },
87	    isLoading: false,
88	    isError: false,
89	    error: null,
90	  } as unknown as ReturnType<typeof useMarkets>;
91	}
92	
93	// ---------------------------------------------------------------------------
94	// Helpers
95	// ---------------------------------------------------------------------------
96	
97	/**
98	 * Render AssumptionPanel wrapped in a local AssumptionProvider.
99	 * Optionally pre-populate assumptions via an `init` callback that fires
100	 * before the component under test mounts — we achieve this by rendering a
101	 * small bootstrapper that calls addAssumption inside an effect-free click.
102	 */
103	function renderPanel(
104	  { market = currentMarket, initialAssumptions = [] as Array<{ variableId: string; outcomeId: string; label: string }> } = {},
105	) {
106	  // We wrap in AssumptionProvider locally (decision d5).
107	  // To pre-seed assumptions, we render a helper button that adds them.
108	  function Wrapper() {
109	    return (
110	      <AssumptionProvider>
111	        <Seeder assumptions={initialAssumptions} />
112	        <AssumptionPanel market={market} />
113	      </AssumptionProvider>
114	    );
115	  }
116	
117	  return renderWithProviders(<Wrapper />);
118	}
119	
120	/**
121	 * Invisible component that seeds assumptions into context when its
122	 * "seed-assumptions" button is clicked.
123	 */
124	function Seeder({ assumptions }: { assumptions: Array<{ variableId: string; outcomeId: string; label: string }> }) {
125	  const { addAssumption } = useAssumptions();
126	  return (
127	    <button
128	      data-testid="seed-assumptions"
129	      onClick={() => assumptions.forEach((a) => addAssumption(a))}
130	      style={{ display: "none" }}
131	    />
132	  );
133	}
134	
135	function seedAssumptions() {
136	  fireEvent.click(screen.getByTestId("seed-assumptions"));
137	}
138	
139	// ---------------------------------------------------------------------------
140	// Setup
141	// ---------------------------------------------------------------------------
142	
143	beforeEach(() => {
144	  vi.clearAllMocks();
145	  mockUseMarkets.mockReturnValue(threeActiveMarkets());
146	});
147	
148	// ---------------------------------------------------------------------------
149	// Tests
150	// ---------------------------------------------------------------------------
151	
152	describe("AssumptionPanel", () => {
153	  it("renders heading and marginal probabilities status when no assumptions", () => {
154	    renderPanel();
155	
156	    expect(screen.getByText("Variables & Assumptions")).toBeInTheDocument();
157	    expect(screen.getByText("Showing marginal probabilities")).toBeInTheDocument();
158	  });
159	
160	  it("renders correct status text when assumptions are set", () => {
161	    renderPanel({
162	      initialAssumptions: [
163	        { variableId: "var-mkt-b", outcomeId: "mkt-b-yes", label: "Market B" },
164	      ],
165	    });
166	    seedAssumptions();
167	
168	    expect(screen.getByText(/Showing conditionals given 1 assumption$/)).toBeInTheDocument();
169	
170	    // Add a second assumption — use a fresh render to check pluralisation
171	  });
172	
173	  it("renders correct pluralised status for multiple assumptions", () => {
174	    renderPanel({
175	      initialAssumptions: [
176	        { variableId: "var-mkt-b", outcomeId: "mkt-b-yes", label: "Market B" },
177	        { variableId: "var-mkt-c", outcomeId: "mkt-c-yes", label: "Market C" },
178	      ],
179	    });
180	    seedAssumptions();
181	
182	    expect(screen.getByText(/Showing conditionals given 2 assumptions$/)).toBeInTheDocument();
183	  });
184	
185	  it("renders VariableRow for each active market with current market first", () => {
186	    renderPanel();
187	
188	    // 3 VariableRow renders (one per active market)
189	    expect(mockVariableRow).toHaveBeenCalledTimes(3);
190	
191	    // First call should be the current market
192	    expect(mockVariableRow.mock.calls[0]![0]).toMatchObject({
193	      marketId: "mkt-current",
194	    });
195	
196	    // Verify all three are in the document
197	    expect(screen.getByTestId("variable-row-mkt-current")).toBeInTheDocument();
198	    expect(screen.getByTestId("variable-row-mkt-b")).toBeInTheDocument();
199	    expect(screen.getByTestId("variable-row-mkt-c")).toBeInTheDocument();
200	  });
201	
202	  it("shows create-more-markets message when only one active market", () => {
203	    mockUseMarkets.mockReturnValue(singleActiveMarket());
204	    renderPanel();
205	
206	    expect(screen.getByText(/Create more markets to use assumptions/)).toBeInTheDocument();
207	  });
208	
209	  it("hides create-more-markets message when multiple active markets", () => {
210	    mockUseMarkets.mockReturnValue(threeActiveMarkets());
211	    renderPanel();
212	
213	    expect(screen.queryByText(/Create more markets to use assumptions/)).not.toBeInTheDocument();
214	  });
215	
216	  it("AssumptionBar shows assumption tags with GIVEN label", () => {
217	    renderPanel({
218	      initialAssumptions: [
219	        { variableId: "var-mkt-b", outcomeId: "mkt-b-yes", label: "Market B" },
220	      ],
221	    });
222	    seedAssumptions();
223	
224	    expect(screen.getByText("GIVEN:")).toBeInTheDocument();
225	    expect(screen.getByText(/Market B/)).toBeInTheDocument();
226	  });
227	
228	  it("AssumptionBar hidden when no assumptions", () => {
229	    renderPanel();
230	
231	    expect(screen.queryByText("GIVEN:")).not.toBeInTheDocument();
232	  });
233	
234	  it("clear all button removes all assumptions", () => {
235	    renderPanel({
236	      initialAssumptions: [
237	        { variableId: "var-mkt-b", outcomeId: "mkt-b-yes", label: "Market B" },
238	        { variableId: "var-mkt-c", outcomeId: "mkt-c-yes", label: "Market C" },
239	      ],
240	    });
241	    seedAssumptions();
242	
243	    // Verify assumptions are present
244	    expect(screen.getByText("GIVEN:")).toBeInTheDocument();
245	    expect(screen.getByText(/Showing conditionals given 2 assumptions/)).toBeInTheDocument();
246	
247	    // Click "Clear all"
248	    fireEvent.click(screen.getByText("Clear all"));
249	
250	    // After clearing, should revert to marginal
251	    expect(screen.getByText("Showing marginal probabilities")).toBeInTheDocument();
252	    expect(screen.queryByText("GIVEN:")).not.toBeInTheDocument();
253	  });
254	
255	  it("remove individual assumption via tag close button", () => {
256	    renderPanel({
257	      initialAssumptions: [
258	        { variableId: "var-mkt-b", outcomeId: "mkt-b-yes", label: "Market B" },
259	        { variableId: "var-mkt-c", outcomeId: "mkt-c-yes", label: "Market C" },
260	      ],
261	    });
262	    seedAssumptions();
263	
264	    // Both should be present
265	    expect(screen.getByText(/Market B/)).toBeInTheDocument();
266	    expect(screen.getByText(/Market C/)).toBeInTheDocument();
267	
268	    // Click remove on Market B's tag
269	    fireEvent.click(screen.getByLabelText("Remove assumption Market B"));
270	
271	    // Market B should be gone, Market C should remain
272	    expect(screen.queryByText(/Market B = mkt-b-yes/)).not.toBeInTheDocument();
273	    expect(screen.getByText(/Market C/)).toBeInTheDocument();
274	    expect(screen.getByText(/Showing conditionals given 1 assumption$/)).toBeInTheDocument();
275	  });
276	});
