import { useAssumptions } from "./AssumptionContext";

export function AssumptionBar() {
  const { assumptions, removeAssumption, clearAll } = useAssumptions();

  if (assumptions.length === 0) return null;

  return (
    <div style={barStyle}>
      <span style={{ fontSize: "0.75rem", fontWeight: 600, color: "var(--color-text-muted)", marginRight: 8 }}>
        GIVEN:
      </span>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, flex: 1 }}>
        {assumptions.map((a) => (
          <span key={a.variableId} style={tagStyle}>
            {a.label} = {a.outcomeId}
            <button
              onClick={() => removeAssumption(a.variableId)}
              style={tagCloseStyle}
              aria-label={`Remove assumption ${a.label}`}
            >
              ×
            </button>
          </span>
        ))}
      </div>
      <button onClick={clearAll} style={clearBtnStyle}>
        Clear all
      </button>
    </div>
  );
}
```

**Key Features:**
- Returns `null` when no assumptions exist
- Displays "GIVEN:" label with assumption tags
- Each tag shows `label = outcomeId`
- Individual removal button per tag with `×` symbol
- "Clear all" button to reset all assumptions
- Styled with inline CSS properties and CSS variables

---

### 2. **AssumptionContext & useAssumptions Hook** (`frontend/src/features/assumptions/AssumptionContext.tsx`)

**Full Source:**
```tsx
import { createContext, useContext, useState, useCallback, type ReactNode } from "react";

export interface Assumption {
  variableId: string;
  outcomeId: string;
  /** Display label for the assumption */
  label: string;
}

interface AssumptionState {
  assumptions: Assumption[];
  addAssumption: (a: Assumption) => void;
  removeAssumption: (variableId: string) => void;
  clearAll: () => void;
  hasAssumption: (variableId: string) => boolean;
  getAssumption: (variableId: string) => Assumption | undefined;
  /** Context array for API calls */
  contextPayload: Array<{ variableId: string; outcomeId: string }>;
}

const AssumptionCtx = createContext<AssumptionState | null>(null);

export function AssumptionProvider({ children }: { children: ReactNode }) {
  const [assumptions, setAssumptions] = useState<Assumption[]>([]);

  const addAssumption = useCallback((a: Assumption) => {
    setAssumptions((prev) => {
      const filtered = prev.filter((p) => p.variableId !== a.variableId);
      return [...filtered, a];
    });
  }, []);

  const removeAssumption = useCallback((variableId: string) => {
    setAssumptions((prev) => prev.filter((p) => p.variableId !== variableId));
  }, []);

  const clearAll = useCallback(() => setAssumptions([]), []);

  const hasAssumption = useCallback(
    (variableId: string) => assumptions.some((a) => a.variableId === variableId),
    [assumptions],
  );

  const getAssumption = useCallback(
    (variableId: string) => assumptions.find((a) => a.variableId === variableId),
    [assumptions],
  );

  const contextPayload = assumptions.map((a) => ({
    variableId: a.variableId,
    outcomeId: a.outcomeId,
  }));

  return (
    <AssumptionCtx.Provider
      value={{ assumptions, addAssumption, removeAssumption, clearAll, hasAssumption, getAssumption, contextPayload }}
    >
      {children}
    </AssumptionCtx.Provider>
  );
}

export function useAssumptions() {
  const ctx = useContext(AssumptionCtx);
  if (!ctx) throw new Error("useAssumptions must be used within AssumptionProvider");
  return ctx;
}
```

**Key Points:**
- `Assumption` interface: `{ variableId, outcomeId, label }`
- `contextPayload`: strips the `label` for API calls
- `addAssumption` replaces existing assumption with same `variableId` (not additive)
- All methods are useCallback-memoized
- Error thrown if hook used outside provider

---

### 3. **AssumptionPanel Component** (`frontend/src/features/assumptions/AssumptionPanel.tsx`)

**Full Source:**
```tsx
import { useMarkets } from "@/lib/query/hooks";
import { useAssumptions } from "./AssumptionContext";
import { AssumptionBar } from "./AssumptionBar";
import { VariableRow } from "./VariableRow";
import type { Market } from "@/lib/api/types";

interface AssumptionPanelProps {
  market: Market;
}

export function AssumptionPanel({ market }: AssumptionPanelProps) {
  const { data: marketsData } = useMarkets();
  const { assumptions } = useAssumptions();

  const allMarkets = marketsData?.markets ?? [];
  const activeMarkets = allMarkets.filter((m) => m.status === "active");

  // Show current market first, then others
  const sortedIds = [
    market.id,
    ...activeMarkets.filter((m) => m.id !== market.id).map((m) => m.id),
  ];

  return (
    <div style={panelStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "var(--space-sm)" }}>
        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
          Variables & Assumptions
        </h3>
        <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
          {assumptions.length > 0
            ? `Showing conditionals given ${assumptions.length} assumption${assumptions.length > 1 ? "s" : ""}`
            : "Showing marginal probabilities"}
        </span>
      </div>

      <AssumptionBar />

      <div style={{ display: "grid", gap: "var(--space-sm)", marginTop: "var(--space-sm)" }}>
        {sortedIds.map((id) => (
          <VariableRow key={id} marketId={id} targetMarket={market} />
        ))}
      </div>

      {activeMarkets.length <= 1 && (
        <div style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-md)" }}>
          Create more markets to use assumptions — assumptions let you condition on other variables.
        </div>
      )}
    </div>
  );
}
```

**Component Hierarchy:**
- `AssumptionPanel` displays the entire panel
- Contains `AssumptionBar` (renders at top if assumptions exist)
- Contains multiple `VariableRow` components (one per active market)
- Status text shows assumption count and changes from "marginal probabilities" to "conditionals given N assumption(s)"

---

### 4. **VariableRow Component** (`frontend/src/features/assumptions/VariableRow.tsx`)

**Key Functionality:**
- Fetches market data via `useMarket(marketId)`
- Uses `useAssumptions()` to add/remove/check assumptions
- Renders assumption "Assume" button (only on non-target markets)
- Renders "Edit" button for probability adjustment (only if session configured)
- Shows inline slider and Set/Cancel buttons in edit mode
- Calls `useProbabilityEdit` mutation for API submission
- Displays success/error feedback with orderId or error message
- Uses `contextPayload` from assumptions when submitting edits

